465	func buildUsage(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) *ProviderUsage {
466		counts := agent.AggregateUsageCounts(entries, name, kind, now)
467		// FEAT-014 no-fabrication: when the session index has no rows attributable
468		// to this name, return nil so the UI renders "not reported" instead of
469		// fabricated "0 / 0" counts.
470		if counts.TokensLastHour == 0 && counts.TokensLast24h == 0 &&
471			counts.RequestsLastHour == 0 && counts.RequestsLast24h == 0 {
472			return nil
473		}
474		u := &ProviderUsage{}
475		v := counts.TokensLastHour
476		u.TokensUsedLastHour = &v
477		v2 := counts.TokensLast24h
478		u.TokensUsedLast24h = &v2
479		v3 := counts.RequestsLastHour
480		u.RequestsLastHour = &v3
481		v4 := counts.RequestsLast24h
482		u.RequestsLast24h = &v4
483		return u
484	}
